+// ─── Particle system ───────────────────────────────────────────────
+
+interface Particle { x: number; y: number; vx: number; vy: number; life: number; maxLife: number; color: string; size: number }
+const particlePool = new Map<string, Particle[]>();
+function getParticles(id: string) { if (!particlePool.has(id)) particlePool.set(id, []); return particlePool.get(id)!; }
+function spawnParticle(id: string, x: number, y: number, color: string, vx = 0, vy = -0.5, size = 2, life = 60) {
+  const p = getParticles(id);
+  if (p.length > 30) return;
+  p.push({ x, y, vx: vx + (Math.random() - 0.5) * 0.3, vy, life, maxLife: life, color, size });
+}
+function updateAndDrawParticles(ctx: CanvasRenderingContext2D, id: string) {
+  const arr = getParticles(id);
+  for (let i = arr.length - 1; i >= 0; i--) {
+    const p = arr[i];
+    p.x += p.vx; p.y += p.vy; p.life--;
+    if (p.life <= 0) { arr.splice(i, 1); continue; }
+    ctx.globalAlpha = p.life / p.maxLife;
+    ctx.fillStyle = p.color;
+    ctx.fillRect(Math.round(p.x), Math.round(p.y), p.size, p.size);
+  }
+  ctx.globalAlpha = 1;
+}
+
+function drawRoomParticles(ctx: CanvasRenderingContext2D, roomType: string, bounds: { x: number; y: number; w: number; h: number }, frame: number) {
+  const id = `room-${roomType}`;
+  const particles = getParticles(id);
+
+  // Spawn new particles based on room type and frame timing
+  switch (roomType) {
+    case 'Workshop': {
+      // Orange forge sparks rising and fading
+      if (particles.length < 30 && Math.random() < 0.3) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + bounds.h - 4;
+        const vx = (Math.random() - 0.5) * 0.2;
+        const vy = -0.7 - Math.random() * 0.3;
+        const color = `rgba(255, ${140 + Math.floor(Math.random() * 60)}, 0, 1)`;
+        const size = 1 + Math.random();
+        const life = 40 + Math.floor(Math.random() * 20);
+        spawnParticle(id, x, y, color, vx, vy, size, life);
+      }
+      break;
+    }
+    case 'Healing Chamber': {
+      // Green healing sparkles floating upward
+      if (particles.length < 30 && Math.random() < 0.25) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + bounds.h - 2;
+        const vx = (Math.random() - 0.5) * 0.1;
+        const vy = -0.3 - Math.random() * 0.2;
+        const green = 180 + Math.floor(Math.random() * 75);
+        const color = `rgba(0, ${green}, 0, 1)`;
+        const size = 1 + Math.random();
+        const life = 50 + Math.floor(Math.random() * 30);
+        spawnParticle(id, x, y, color, vx, vy, size, life);
+      }
+      break;
+    }
+    case 'Library': {
+      // Dust motes drifting slowly
+      if (particles.length < 20 && Math.random() < 0.15) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + Math.random() * bounds.h;
+        const vx = (Math.random() - 0.5) * 0.05;
+        const vy = (Math.random() - 0.5) * 0.02;
+        const color = `rgba(200, 180, 150, 0.6)`;
+        const size = 1;
+        const life = 80 + Math.floor(Math.random() * 40);
+        spawnParticle(id, x, y, color, vx, vy, size, life);
+      }
+      break;
+    }
+    case 'Dungeon': {
+      // Dripping water droplets falling
+      if (particles.length < 25 && Math.random() < 0.2) {
+        const x = bounds.x + Math.random() * bounds.w;
+        const y = bounds.y + 2;
+        const vx = 0;
+        const vy = 0.7 + Math.random() * 0.3;
+        const color = `rgba(180, 220, 255, 0.8)`;
+        const size = 1 + Math.random();
+        const life = 50 + Math.floor(Math.random() * 20);
+        spawnParticle(id, x, y, color, vx, vy, size, life);
+      }
+      break;
+    }
+    case 'Watchtower': {
+      // Wind streaks moving horizontally
+      if (particles.length < 20 && Math.random() < 0.25) {
+        const y = bounds.y + Math.random() * bounds.h;
+        const x = bounds.x + (Math.random() < 0.5 ? bounds.w + 2 : -2);
+        const vx = (x < bounds.x) ? 0.5 + Math.random() * 0.3 : -0.5 - Math.random() * 0.3;
+        const vy = 0;
+        const color = `rgba(180, 200, 255, 0.5)`;
+        const size = 2;
+        const life = Math.floor(bounds.w / Math.abs(vx));
+        spawnParticle(id, x, y, color, vx, vy, size, life);
+      }
+      break;
+    }
+  }
+
+  // Update and draw all particles for this room
+  for (let i = particles.length - 1; i >= 0; i--) {
+    const p = particles[i];
+    p.x += p.vx;
+    p.y += p.vy;
+    p.life--;
+    if (p.life <= 0) {
+      particles.splice(i, 1);
+      continue;
+    }
+    ctx.globalAlpha = p.life / p.maxLife;
+    ctx.fillStyle = p.color;
+    ctx.fillRect(Math.round(p.x), Math.round(p.y), p.size, p.size);
+  }
+  ctx.globalAlpha = 1;
+}
